class Solution:
    def canWinNim(self, n):
        # Independent derivation: build the game-theory table only far enough
        # to expose its period, then index into one cycle. win[k] is True when
        # some move (remove 1, 2 or 3) hands the opponent a losing position.
        win = [False, True, True, True]
        for k in range(4, 8):
            win.append(not (win[k - 1] and win[k - 2] and win[k - 3]))
        period = 4
        return win[n % period]

